func TestRustExtractorAuditableSection(t *testing.T) {
	// Build a tiny ELF with a `.dep-v0` zlib-compressed JSON section.
	manifestJSON := `{
		"packages": [
			{"name": "rocket", "version": "0.5.0", "root": true},
			{"name": "tokio",  "version": "1.35.0"},
			{"name": "serde",  "version": "1.0.190"}
		]
	}`
	body := buildELFWithSection(t, ".dep-v0", zlibCompress(t, []byte(manifestJSON)))

	id, err := (&RustExtractor{}).Extract(context.Background(), File{Body: body})
	if err != nil {
		t.Fatalf("Extract: %v", err)
	}
	if id.Name != "rocket" || id.Version != "0.5.0" {
		t.Errorf("identity = %+v", id)
	}
	if id.PURL != "pkg:cargo/rocket@0.5.0" {
		t.Errorf("PURL = %q", id.PURL)
	}
	if len(id.SubComponents) != 2 {
		t.Errorf("SubComponents count = %d, want 2", len(id.SubComponents))
	}
	if id.Properties["rust.dep.count"] != "2" {
		t.Errorf("dep.count = %q", id.Properties["rust.dep.count"])
	}
}

