// S4 Task 0: the PE filename pattern (`name-1.2.3.exe`) was removed
// because the filename is not a verifiable identity. Without
// VS_VERSIONINFO parsing the extractor surfaces no Identity at all
// for well-formed PE files; the untracked enricher records them as
// observed-only.
func TestPEExtractorNoFilenameFallback(t *testing.T) {
	// A minimally valid PE that debug/pe will parse — just the MZ
	// magic followed by the PE header at offset 0x80. We don't need a
	// real binary; debug/pe.NewFile only requires the structure to be
	// walkable. If parsing fails the extractor returns empty too, so
	// either way the assertion holds.
	body := []byte{'M', 'Z'}
	id, err := (&PEExtractor{}).Extract(context.Background(), File{
		Path: "opt/myapp-1.2.3.exe",
		Body: body,
	})
	if err != nil {
		t.Fatalf("Extract: %v", err)
	}
	if !id.IsEmpty() {
		t.Errorf("Identity = %+v, want empty (filename fallback removed)", id)
	}
}

// ─── Helpers ────────────────────────────────────────────────────────

func buildJAR(t *testing.T, files map[string]string) []byte {
	t.Helper()
	var buf bytes.Buffer
	zw := zip.NewWriter(&buf)
	for name, body := range files {
		w, err := zw.Create(name)
		if err != nil {
			t.Fatal(err)
		}
		if _, err := w.Write([]byte(body)); err != nil {
			t.Fatal(err)
		}
	}
	if err := zw.Close(); err != nil {
		t.Fatal(err)
	}
	return buf.Bytes()
}

func zlibCompress(t *testing.T, body []byte) []byte {
	t.Helper()
	var buf bytes.Buffer
	zw := zlib.NewWriter(&buf)
	if _, err := zw.Write(body); err != nil {
		t.Fatal(err)
	}
	if err := zw.Close(); err != nil {
		t.Fatal(err)
	}
	return buf.Bytes()
}

// buildMinimalELF returns a tiny but well-formed 64-bit ELF file
// with no sections beyond the SHT_NULL header. Enough to satisfy
// debug/elf.NewFile so extractors can probe sections without
// crashing.
func buildMinimalELF(t *testing.T) []byte {
	t.Helper()
	return buildELFWithSection(t, "", nil)
}

// buildELFWithSection returns an ELF64 file carrying ONE custom
// section with the given name and contents (when sectionName is
// "", the file has no custom section). Used for the Rust auditable
// fixture; deliberately bare-bones — just enough for debug/elf to
// parse and surface the section.
func buildELFWithSection(t *testing.T, sectionName string, sectionData []byte) []byte {
	t.Helper()

	const (
		ehSize = 64
		phSize = 0
		shSize = 64
	)

	// Section layout:
	//   [0] SHT_NULL
	//   [1] section .shstrtab
	//   [2] custom section (only when sectionName != "")
	hasCustom := sectionName != ""
	numSections := uint16(2)
	if hasCustom {
		numSections = 3
	}

	// Build .shstrtab — null + ".shstrtab\0" + (optional) "<sectionName>\0"
	var shstr bytes.Buffer
	shstr.WriteByte(0) // index 0 = empty string
	shstrtabNameOff := uint32(shstr.Len())
	shstr.WriteString(".shstrtab")
	shstr.WriteByte(0)
	customNameOff := uint32(0)
	if hasCustom {
		customNameOff = uint32(shstr.Len())
		shstr.WriteString(sectionName)
		shstr.WriteByte(0)
	}

	// Compute section file offsets. Section table follows the
	// data blob.
	dataStart := uint64(ehSize)
	shstrtabOffset := dataStart
	customOffset := uint64(0)
	cursor := shstrtabOffset + uint64(shstr.Len())
	if hasCustom {
		customOffset = cursor
		cursor += uint64(len(sectionData))
	}
	shoff := cursor

	// Total size = section table end.
	totalSize := int(shoff) + int(numSections)*shSize

	out := make([]byte, totalSize)

	// ELF header.
	copy(out[0:], []byte{0x7f, 'E', 'L', 'F'})
	out[4] = 2 // ELFCLASS64
	out[5] = 1 // ELFDATA2LSB
	out[6] = 1 // EV_CURRENT
	out[7] = 0 // OSABI System V
	// e_type=ET_DYN (3), e_machine=EM_X86_64 (62)
	binary.LittleEndian.PutUint16(out[16:], 3)
	binary.LittleEndian.PutUint16(out[18:], 62)
	binary.LittleEndian.PutUint32(out[20:], 1) // e_version
	// e_entry / e_phoff / e_shoff
	binary.LittleEndian.PutUint64(out[24:], 0)
	binary.LittleEndian.PutUint64(out[32:], 0)
	binary.LittleEndian.PutUint64(out[40:], shoff)
	binary.LittleEndian.PutUint32(out[48:], 0)           // e_flags
	binary.LittleEndian.PutUint16(out[52:], ehSize)      // e_ehsize
	binary.LittleEndian.PutUint16(out[54:], phSize)      // e_phentsize
	binary.LittleEndian.PutUint16(out[56:], 0)           // e_phnum
	binary.LittleEndian.PutUint16(out[58:], shSize)      // e_shentsize
	binary.LittleEndian.PutUint16(out[60:], numSections) // e_shnum
	binary.LittleEndian.PutUint16(out[62:], 1)           // e_shstrndx — index of .shstrtab

	// Section data.
	copy(out[shstrtabOffset:], shstr.Bytes())
	if hasCustom {
		copy(out[customOffset:], sectionData)
	}

	// Section headers.
	writeSectionHeader := func(idx int, nameOff uint32, typ uint32, off, size uint64) {
		base := int(shoff) + idx*shSize
		binary.LittleEndian.PutUint32(out[base+0:], nameOff)
		binary.LittleEndian.PutUint32(out[base+4:], typ)
		binary.LittleEndian.PutUint64(out[base+8:], 0)  // flags
		binary.LittleEndian.PutUint64(out[base+16:], 0) // addr
		binary.LittleEndian.PutUint64(out[base+24:], off)
		binary.LittleEndian.PutUint64(out[base+32:], size)
		binary.LittleEndian.PutUint32(out[base+40:], 0) // link
		binary.LittleEndian.PutUint32(out[base+44:], 0) // info
		binary.LittleEndian.PutUint64(out[base+48:], 1) // addralign
		binary.LittleEndian.PutUint64(out[base+56:], 0) // entsize
	}
	writeSectionHeader(0, 0, 0 /*SHT_NULL*/, 0, 0)
	writeSectionHeader(1, shstrtabNameOff, uint32(elf.SHT_STRTAB), shstrtabOffset, uint64(shstr.Len()))
	if hasCustom {
		writeSectionHeader(2, customNameOff, uint32(elf.SHT_PROGBITS), customOffset, uint64(len(sectionData)))
	}

	// Sanity: parse our own output to catch obviously wrong shapes
	// before the test's real assertions trip.
	if _, err := elf.NewFile(bytes.NewReader(out)); err != nil {
		t.Fatalf("buildELFWithSection produced invalid ELF: %v", err)
	}
	return out
}

// silence the unused-import warning for builds that don't reach the
// Rust test path.
var _ = strings.Contains
